#include <bits/stdc++.h>
using namespace std;
int main() {
    int K;
    cin >> K;
    vector<vector<int>> nums;
    int total_elements = 0;
    for (int i = 0; i < K; i++) {
        int N;
        cin >> N;
        total_elements += N;
        vector<int> inner_array(N);
        for (int j = 0; j < N; j++) {
            cin >> inner_array[j];
        }
        nums.push_back(inner_array);
    }
    vector<int> flat_nums;
    for (const auto& inner_array : nums) {
        flat_nums.insert(flat_nums.end(), inner_array.begin(), inner_array.end());
    }
    sort(flat_nums.begin(), flat_nums.end());
    cout << total_elements << endl;
    for (const auto& num : flat_nums) {
        cout << num << ' ';
    }
    return 0;
}
